// Normaliza a resposta do backend (array de agendamentos) e monta 1 mensagem
// por destinatario (cliente e barbeiro), so quando ha telefone.
const entrada = $input.all();
let agendamentos = [];
for (const it of entrada) {
  const j = it.json;
  if (Array.isArray(j)) agendamentos.push(...j);
  else if (j && Array.isArray(j.data) && j.data[0] && j.data[0].cliente) agendamentos.push(...j.data);
  else if (j && j.cliente) agendamentos.push(j);
}

function tel(t) {
  if (!t) return null;
  const n = String(t).replace(/\D/g, '');
  if (n.length < 10) return null;
  return n.startsWith('55') ? n : ('55' + n);
}

const saida = [];
for (const a of agendamentos) {
  const servicos = (a.servicos || []).join(', ');
  const clienteTel = tel(a.cliente && a.cliente.telefone);
  if (clienteTel) {
    saida.push({ json: {
      number: clienteTel,
      text: `Ola ${a.cliente.nome || ''}! ⏰ Lembrete: voce tem horario na ${a.barbearia} hoje as ${a.horario}` + (servicos ? ` (${servicos})` : '') + `. Ate ja! ✂️`
    }});
  }
  const barbeiroTel = tel(a.barbeiro && a.barbeiro.telefone);
  if (barbeiroTel) {
    saida.push({ json: {
      number: barbeiroTel,
      text: `Ola ${(a.barbeiro && a.barbeiro.nome) || ''}! ⏰ Lembrete: ${a.cliente.nome || 'cliente'} tem horario as ${a.horario}` + (servicos ? ` (${servicos})` : '') + `.`
    }});
  }
}
return saida;
